PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?cls ?label WHERE {
  ?cls a <http://www.w3.org/2002/07/owl#Class> .
  ?cls rdfs:label ?label .
  FILTER(CONTAINS(LCASE(STR(?label)), "copper"))
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?cls ?label ?comment WHERE {
  ?cls a <http://www.w3.org/2002/07/owl#Class> .
  OPTIONAL { ?cls rdfs:label ?label }
  OPTIONAL { ?cls rdfs:comment ?comment }
  FILTER(CONTAINS(LCASE(STR(?label)), "copper") || CONTAINS(LCASE(STR(?comment)), "copper"))
}

