PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl:  <http://www.w3.org/2002/07/owl#>
SELECT ?cls ?parent ?label ?comment WHERE {
  ?cls a owl:Class .
  ?cls rdfs:subClassOf ?parent .
  OPTIONAL { ?cls rdfs:label ?label }
  OPTIONAL { ?cls rdfs:comment ?comment }
  FILTER(CONTAINS(STR(?parent), "V0301030105"))
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl:  <http://www.w3.org/2002/07/owl#>
SELECT ?cls ?parent ?label ?comment WHERE {
  ?cls a owl:Class .
  OPTIONAL { ?cls rdfs:subClassOf ?parent }
  OPTIONAL { ?cls rdfs:label ?label }
  OPTIONAL { ?cls rdfs:comment ?comment }
  FILTER(
    CONTAINS(LCASE(COALESCE(STR(?comment), "")), "2030")
  )
}

